func:
// ปรับปรุงการรับข้อมูล: เช็กชนิดข้อมูลก่อนเพื่อป้องกันบั๊ก [object Object]
var adminData;

if (typeof msg.payload === "string") {
    // ถ้าข้อมูลมาเป็นข้อความ String ให้ทำการแปลงเป็น Object
    try {
        adminData = JSON.parse(msg.payload);
    } catch(e) {
        node.error("ข้อมูล String ที่ส่งมาไม่ใช่รูปแบบ JSON ที่ถูกต้อง");
        return null;
    }
} else if (typeof msg.payload === "object") {
    // ถ้าข้อมูลถูกแปลงมาเป็น Object เรียบร้อยแล้ว ให้ดึงไปใช้งานได้ทันทีเลย
    adminData = msg.payload;
}

// ==========================================
// ส่วนลอจิกควบคุมระบบ (คงเดิมตามสเปก)
// ==========================================
if (adminData.action === "register") {
    // บันทึกชื่อทีมลงในลิ้นชักความจำของ Flow
    flow.set("current_team", adminData.team_name);

    // สร้าง Payload ใหม่เพื่อตัดข้อมูลเซสชันเก่า ป้องกันการล็อกหน้าจอ (ทำ Broadcast)
    var msgTeam = { payload: adminData.team_name };
    var msgStatus = { payload: "READY" };
    var msgMqtt = { payload: "READY" };

    return [msgTeam, msgStatus, msgMqtt];
} 
else if (adminData.action === "reset") {
    // 1. ล้างค่าชื่อทีมในระบบความจำส่วนกลาง
    flow.set("current_team", "");

    // 2. สร้างกล่องข้อความว่างเปล่า เพื่อส่งไปสั่งให้หน้าจอใหญ่ล้างชื่อทีมทิ้ง
    var msgClearTeam = { payload: "" };

    // 3. สร้างกล่องข้อความคำว่า RESET เพื่อสั่งเปลี่ยนสถานะจอ และสั่งบอร์ดสนาม
    var msgReset = { payload: "RESET" };

    // 4. ส่งข้อมูลออก 3 รูพร้อมกัน (คราวนี้รูที่ 1 จะไม่เป็น null แล้ว จะส่งค่าว่างไปเคลียร์จอ)
    return [msgClearTeam, msgReset, msgReset];
}









// // บรรทัดที่ 1: แปลงข้อความดิบ (String JSON) ที่แอดมินส่งมา ให้กลายเป็น Object ของ JavaScript เพื่อให้ดึง Property ข้างในมาใช้งานได้ง่าย
// var adminData = JSON.parse(msg.payload);

// // บรรทัดที่ 2: ตรวจสอบเงื่อนไขว่า ถ้าแอดมินส่งคำสั่งประเภทลงทะเบียนทีมวิ่ง (register) เข้ามา
// if (adminData.action === "register") {

//     // บรรทัดที่ 3: ดึงชื่อทีมจากข้อมูลแอดมิน แล้วนำไปฝากไว้ในตัวแปรระบบระดับ Flow (ลิ้นชักความจำภายในแท็บนี้) 
//     // เพื่อให้โหนดกลุ่มอื่นๆ (เช่น ตอนที่รถเข้าเส้นชัยแล้วได้เวลา) สามารถแวะมาดึงชื่อทีมนี้ไปใช้บันทึกร่วมกับตัวเลขเวลาได้
//     flow.set("current_team", adminData.team_name);

//     // บรรทัดที่ 4-6: **จุดสำคัญมาก** เราทำการสร้าง Object ใหม่เอี่ยม `{ payload: ... }` ขึ้นมาดื้อๆ 
//     // เหตุผลเพราะว่า ข้อมูลที่หลุดมาจากโหนด websocket in จะมีข้อมูลที่ชื่อว่า `msg._session` ติดมาด้วย (เป็น ID ของหน้าจอแอดมิน)
//     // ถ้าเราใช้ msg ตัวเดิมส่งต่อไปยังหน้าจอแสดงผลหลัก ตัว Node-RED จะเข้าใจผิดว่าต้องส่งกลับไปหาแอดมินคนเดิมเท่านั้น
//     // การสร้างกล่องข้อมูลใหม่เอี่ยมแบบนี้ จะเป็นการสลัด ID เซสชันทิ้ง ทำให้เกิดการ Broadcast (หว่านกระจาย) ไปยังทุกๆ หน้าจอที่เปิดค้างไว้ครับ
//     var msgTeam = { payload: adminData.team_name };
//     var msgStatus = { payload: "READY" };
//     var msgMqtt = { payload: "READY" };

//     // บรรทัดที่ 7: คืนค่าผลลัพธ์ออกเป็นอาเรย์กระจายออกไปทั้งหมด 3 รูตามลำดับ 
//     // รูที่ 1 ได้ชื่อทีม, รูที่ 2 ได้สถานะ READY, รูที่ 3 ได้ข้อความส่งหาบอร์ดสนาม
//     return [msgTeam, msgStatus, msgMqtt];
// }

// // บรรทัดที่ 8: แต่ถ้าหากแอดมินไม่ได้กดลงทะเบียน แต่กดปุ่มล้างระบบ (reset) เพื่อเคลียร์บอร์ดเตรียมแข่งรอบใหม่
// else if (adminData.action === "reset") {

//     // บรรทัดที่ 9: ล้างค่าตัวแปรชื่อทีมในระบบชั่วคราวให้กลับไปเป็นค่าว่างเปล่า ป้องกันข้อมูลทีมเก่าค้างในระบบ
//     flow.set("current_team", "");

//     // บรรทัดที่ 10: สร้างกล่องข้อมูลสถานะ "RESET" เพื่อส่งออกไปสั่งให้หน้าจอใหญ่ล้างจอ และส่งให้ MQTT ไปเคลียร์ค่าบอร์ดเซนเซอร์สนาม
//     var msgReset = { payload: "RESET" };

//     // บรรทัดที่ 11: คืนค่าออกไปเฉพาะช่องที่ 2 และ 3 (ช่องที่ 1 ที่เป็นชื่อทีมส่งเป็น null ไว้เพราะไม่มีข้อมูลส่งไป)
//     return [null, msgReset, msgReset];
// }

// บรรทัดที่ 1: วิ่งไปเปิดลิ้นชักความจำส่วนกลางของแท็บนี้ (Flow Context) เพื่อหยิบชื่อทีมที่แอดมินลงทะเบียนไว้ในส่วนที่ 1
var currentTeamName = msg.team_name;

// บรรทัดที่ 2: นำข้อมูลเวลาดิบที่ส่งมาจาก MQTT (เช่น "12.345") มาแปลงค่าให้เป็นตัวเลขทศนิยม (Float) เพื่อความเที่ยงตรง
var officialTime = parseFloat(msg.payload);

// บรรทัดที่ 3: [ระบบดักบั๊ก] ตรวจสอบว่าถ้าลิ้นชักชื่อทีมว่างเปล่า (แอดมินลืมกดลงทะเบียนทีมแต่ปล่อยรถวิ่ง) ให้หยุดทำงานทันที
if (!currentTeamName) {
    node.warn("MySQL Insert ถูกระงับ: เนื่องจากไม่มีชื่อทีมในระบบ (current_team ว่างเปล่า)");
    return null; // การส่ง null หมายถึงการตัดกระแสไฟ ไม่ให้ส่งข้อมูลไปโหนดถัดไป
}

// บรรทัดที่ 4: [ระบบดักบั๊ก] ตรวจสอบว่าค่าเวลาที่ได้มาจากบอร์ดสนาม เพี้ยนหรือไม่ได้มาเป็นตัวเลขหรือไม่ ถ้าเพี้ยนให้หยุดทำงาน
if (isNaN(officialTime)) {
    node.warn("MySQL Insert ถูกระงับ: ค่าเวลาที่ส่งมาไม่ใช่ตัวเลขที่ใช้งานได้ -> " + msg.payload);
    return null;
}

// บรรทัดที่ 5: **จุดสำคัญของ MySQL** เราจะเขียนคำสั่ง SQL โครงสร้างแบบ Parameterized Query ใส่ไว้ใน msg.topic
// การใช้เครื่องหมายคำถาม (?) เป็นการทำหลุมหลบภัย เพื่อให้โหนด MySQL นำข้อมูลจริงมาเสียบแทนที่ ช่วยป้องกันบั๊กอักขระพิเศษพังระบบ
msg.topic = "INSERT INTO race_results (name, runtime) VALUES (?, ?);";

// บรรทัดที่ 6: นำข้อมูลจริงแพ็กใส่ Array ไว้ใน msg.payload เรียงลำดับตามเครื่องหมาย ? ด้านบน
// currentTeamName จะไปแทนที่ ? ตัวแรก และ officialTime จะไปแทนที่ ? ตัวที่สอง
msg.payload = [currentTeamName, officialTime];

// บรรทัดที่ 7: ส่งกล่องพัสดุนี้ออกไปหาโหนด MySQL
return msg;

// 2. แพ็กคำสั่งแจ้งจบการแข่งขันเตรียมส่งออก รูที่ 2 (ล่าง)
let msgStatus = { payload: "FINISHED" };

// ส่งข้อมูลออกพร้อมกันทั้ง 2 รูแยกจากกัน
return [msgStatus];

// หลังจากเซฟลงฐานข้อมูลสำเร็จ ข้อมูลจะวิ่งมาที่นี่ 
// เราสั่ง SELECT กวาดเอา 10 อันดับที่เวลาดีที่สุด (เรียงจากน้อยไปมาก) ทันที
msg.topic = "SELECT name, runtime FROM race_results ORDER BY runtime ASC LIMIT 10;";
return msg;

// msg.payload ที่ได้กลับมาจากฐานข้อมูลจะเป็นก้อน Array ของทีมที่เร็วที่สุด
let leaderboardArray = msg.payload;

// 1. แพ็กข้อมูลตารางคะแนนเตรียมส่งออก
let msgLeaderboard = { payload: leaderboardArray };


return [msgLeaderboard];
